mapper.select:
SELECT SEQ, RESUME_SEQ, GROUP_NO, GET_CODE_NAME(GROUP_NO, #{lang, jdbcType=VARCHAR}) GROUP_NAME, ITEM_CODE, ITEM_NAME, ITEM_NAME_KO, REMARK, REMARK_KO, ACTIVITY, TO_CHAR(ORDERNO) ORDERNO, TO_CHAR(UPDATE_DATE, 'DD/MM/YYYY HH24:MI') UPDATE_DATE, GET_UPDATED_INFO(UPDATED_BY) || ' ' || UPDATED_IP UPDATED_BY FROM EVS_ITEM A WHERE ACTIVITY <> 2
AND RESUME_SEQ = #{resumeSeq, jdbcType=VARCHAR}
AND GROUP_NO = #{groupNo, jdbcType=VARCHAR}
ORDER BY TO_NUMBER(SEQ)
